import{_ as e,o as s,c as a,a as o}from"./app.8bdf5597.js";const y=JSON.parse(`{"title":"故障排除","description":"","frontmatter":{"title":"故障排除"},"headers":[{"level":2,"title":"CLI","slug":"cli","link":"#cli","children":[{"level":3,"title":"Error: Cannot find module 'C:\\\\foo\\\\bar&baz\\\\vite\\\\bin\\\\vite.js'","slug":"error-cannot-find-module-cfoobarbazvitebinvitejs","link":"#error-cannot-find-module-cfoobarbazvitebinvitejs","children":[]}]},{"level":2,"title":"开发服务器","slug":"dev-server","link":"#dev-server","children":[{"level":3,"title":"请求始终停滞","slug":"requests-are-stalled-forever","link":"#requests-are-stalled-forever","children":[]},{"level":3,"title":"431 Request Header Fields Too Large","slug":"431-request-header-fields-too-large","link":"#431-request-header-fields-too-large","children":[]}]},{"level":2,"title":"HMR","slug":"hmr","link":"#hmr","children":[{"level":3,"title":"Vite 检测到文件变化，但 HMR 不工作","slug":"vite-detects-a-file-change-but-the-hmr-is-not-working","link":"#vite-detects-a-file-change-but-the-hmr-is-not-working","children":[]},{"level":3,"title":"Vite 没有检测到文件变化","slug":"vite-does-not-detect-a-file-change","link":"#vite-does-not-detect-a-file-change","children":[]},{"level":3,"title":"完全重新加载了，而不是 HMR","slug":"a-full-reload-happens-instead-of-hmr","link":"#a-full-reload-happens-instead-of-hmr","children":[]}]},{"level":2,"title":"构建","slug":"build","link":"#build","children":[{"level":3,"title":"构建产物因为 CORS 错误无法工作","slug":"built-file-does-not-work-because-of-cors-error","link":"#built-file-does-not-work-because-of-cors-error","children":[]}]},{"level":2,"title":"其他","slug":"others","link":"#others","children":[{"level":3,"title":"Syntax Error / Type Error","slug":"syntax-error-type-error-happens","link":"#syntax-error-type-error-happens","children":[]}]}],"relativePath":"guide/troubleshooting.md"}`),t={name:"guide/troubleshooting.md"},l=o(`<h1 id="troubleshooting" tabindex="-1">故障排除 <a class="header-anchor" href="#troubleshooting">¶</a></h1><blockquote><p>你还可以查看 <a href="https://rollupjs.org/guide/en/#troubleshooting" target="_blank" rel="noreferrer">Rollup 的故障排除指南</a> 了解更多。</p></blockquote><p>如果这里的建议并未帮助到你，请将你的问题发送到 <a href="https://github.com/vitejs/vite/discussions" target="_blank" rel="noreferrer">GitHub 讨论区</a> 或 <a href="https://chat.vitejs.dev" target="_blank" rel="noreferrer">Vite Land Discord</a> 的 <code>#help</code> 频道。</p><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli">¶</a></h2><h3 id="error-cannot-find-module-cfoobarbazvitebinvitejs" tabindex="-1"><code>Error: Cannot find module &#39;C:\\foo\\bar&amp;baz\\vite\\bin\\vite.js&#39;</code> <a class="header-anchor" href="#error-cannot-find-module-cfoobarbazvitebinvitejs">¶</a></h3><p>你的项目文件夹路径中可能包含了符号 <code>&amp;</code>，这在 Windows 上无法与 <code>npm</code> 配合正常工作 (<a href="https://github.com/npm/cmd-shim/issues/45" target="_blank" rel="noreferrer">npm/cmd-shim#45</a>)。</p><p>你可以选择以下两种修改方式：</p><ul><li>切换另一种包管理工具（例如 <code>pnpm</code> 或 <code>yarn</code>）</li><li>从你的项目路径中移除符号 <code>&amp;</code></li></ul><h2 id="dev-server" tabindex="-1">开发服务器 <a class="header-anchor" href="#dev-server">¶</a></h2><h3 id="requests-are-stalled-forever" tabindex="-1">请求始终停滞 <a class="header-anchor" href="#requests-are-stalled-forever">¶</a></h3><p>如果你使用的是 Linux，文件描述符限制和 inotify 限制可能会导致这个问题。由于 Vite 不会打包大多数文件，浏览器可能会请求许多文件，而相应地需要许多文件描述符，因此超过了限制。</p><p>要解决这个问题：</p><ul><li><p>使用 <code>ulimit</code> 增加文件描述符的限制</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 查看当前限制值</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">ulimit</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-Sn</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># （暂时）更改限制值</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">ulimit</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-Sn</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">10000</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 你可能也需要更改硬性限制值</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 重启你的浏览器</span></span>
<span class="line"></span></code></pre></div></li><li><p>通过 <code>sysctl</code> 提升下列 inotify 相关的限制</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 查看当前限制值</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sysctl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">fs.inotify</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># （暂时）更改限制值</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sysctl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">fs.inotify.max_queued_events=</span><span style="color:#F78C6C;">16384</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sysctl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">fs.inotify.max_user_instances=</span><span style="color:#F78C6C;">8192</span></span>
<span class="line"><span style="color:#FFCB6B;">$</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sysctl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">fs.inotify.max_user_watches=</span><span style="color:#F78C6C;">524288</span></span>
<span class="line"></span></code></pre></div></li></ul><p>如果通过以上步骤仍不起作用，可以尝试在以下文件中添加 <code>DefaultLimitNOFILE=65536</code> 配置。</p><ul><li>/etc/systemd/system.conf</li><li>/etc/systemd/user.conf</li></ul><p>请注意，这些配置会持久作用，但需要 <strong>重新启动</strong>。</p><h3 id="431-request-header-fields-too-large" tabindex="-1">431 Request Header Fields Too Large <a class="header-anchor" href="#431-request-header-fields-too-large">¶</a></h3><p>当服务器或 WebSocket 服务收到一个较大的 HTTP 头，该请求可能会被遗落并且会显示下面这样的警告。</p><blockquote><p>Server responded with status code 431. See <a href="https://vitejs.dev/guide/troubleshooting.html#_431-request-header-fields-too-large" target="_blank" rel="noreferrer">https://vitejs.dev/guide/troubleshooting.html#_431-request-header-fields-too-large</a>.</p></blockquote><p>这是由于 Node.js 限制请求头大小，以减轻 <a href="https://www.cve.org/CVERecord?id=CVE-2018-12121" target="_blank" rel="noreferrer">CVE-2018-12121</a> 的影响。</p><p>要避免这个问题，请尝试减小请求头大小。举个例子，如果 cookie 太长，请删除它。或者你可以使用 <a href="https://nodejs.org/api/cli.html#--max-http-header-sizesize" target="_blank" rel="noreferrer"><code>--max-http-header-size</code></a> 来更改最大请求头大小。</p><h2 id="hmr" tabindex="-1">HMR <a class="header-anchor" href="#hmr">¶</a></h2><h3 id="vite-detects-a-file-change-but-the-hmr-is-not-working" tabindex="-1">Vite 检测到文件变化，但 HMR 不工作 <a class="header-anchor" href="#vite-detects-a-file-change-but-the-hmr-is-not-working">¶</a></h3><p>你可能导入了一个拥有不同大小写的文件，例如，存在 <code>src/foo.js</code> 文件而 <code>src/bar.js</code> 导入了它：</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">./Foo.js</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">// 应该为 &#39;./foo.js&#39;</span></span>
<span class="line"></span></code></pre></div><p>相关 issue：<a href="https://github.com/vitejs/vite/issues/964" target="_blank" rel="noreferrer">#964</a></p><h3 id="vite-does-not-detect-a-file-change" tabindex="-1">Vite 没有检测到文件变化 <a class="header-anchor" href="#vite-does-not-detect-a-file-change">¶</a></h3><p>如果你正在 WSL2 中运行 Vite，Vite 无法在某些场景下监听文件变化。请查看 <a href="/config/server-options.html#server-watch"><code>server.watch</code> 选项</a> 的描述。</p><h3 id="a-full-reload-happens-instead-of-hmr" tabindex="-1">完全重新加载了，而不是 HMR <a class="header-anchor" href="#a-full-reload-happens-instead-of-hmr">¶</a></h3><p>如果 HMR 不是由 Vite 或一个插件处理的，那么将进行完全的重新加载。</p><p>同时如果有依赖环，也会发生完全重载。要解决这个问题，请先尝试解决依赖循环。</p><h2 id="build" tabindex="-1">构建 <a class="header-anchor" href="#build">¶</a></h2><h3 id="built-file-does-not-work-because-of-cors-error" tabindex="-1">构建产物因为 CORS 错误无法工作 <a class="header-anchor" href="#built-file-does-not-work-because-of-cors-error">¶</a></h3><p>如果导出的 HTML 文件是通过 <code>file</code> 协议打开的，那么其中的 script 将不会运行，且报告下列错误。</p><blockquote><p>Access to script at &#39;file:///foo/bar.js&#39; from origin &#39;null&#39; has been blocked by CORS policy: Cross origin requests are only supported for protocol schemes: http, data, isolated-app, chrome-extension, chrome, https, chrome-untrusted.</p></blockquote><blockquote><p>Cross-Origin Request Blocked: The Same Origin Policy disallows reading the remote resource at file:///foo/bar.js. (Reason: CORS request not http).</p></blockquote><p>请查看 <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/CORS/Errors/CORSRequestNotHttp" target="_blank" rel="noreferrer">释因：CORS 请求不是 HTTP 请求 - HTTP | MDN</a> 了解为什么会发生这种情况的更多信息。</p><p>你需要通过 <code>http</code> 协议访问该文件。最简单的办法就是使用 <code>npx vite preview</code>。</p><h2 id="others" tabindex="-1">其他 <a class="header-anchor" href="#others">¶</a></h2><h3 id="syntax-error-type-error-happens" tabindex="-1">Syntax Error / Type Error <a class="header-anchor" href="#syntax-error-type-error-happens">¶</a></h3><p>Vite 无法处理、也不支持仅可在非严格模式（sloppy mode）下运行的代码。这是因为 Vite 使用了 ESM 并且始终在 ESM 中使用 <a href="https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Strict_mode" target="_blank" rel="noreferrer">严格模式</a>。</p><p>例如，你可能会看到以下错误。</p><blockquote><p>[ERROR] With statements cannot be used with the &quot;esm&quot; output format due to strict mode</p></blockquote><blockquote><p>TypeError: Cannot create property &#39;foo&#39; on boolean &#39;false&#39;</p></blockquote><p>如果这些代码是在依赖中被使用的，你应该使用 <a href="https://github.com/ds300/patch-package" target="_blank" rel="noreferrer"><code>patch-package</code></a>（或者 <a href="https://yarnpkg.com/cli/patch" target="_blank" rel="noreferrer"><code>yarn patch</code></a>、<a href="https://pnpm.io/cli/patch" target="_blank" rel="noreferrer"><code>pnpm patch</code></a> 工具）来做短期补丁处理。</p>`,45),r=[l];function n(i,p,c,d,h,u){return s(),a("div",null,r)}const b=e(t,[["render",n]]);export{y as __pageData,b as default};
